// ─── Detecta en qué página estás ──────────────────────
function getPage() {
  const path = window.location.pathname;
  if (path.includes('batman'))                              return 'batman';
  if (path.includes('ecobottle'))                          return 'ecobottle';
  if (path.includes('encuetroCafe') || path.includes('cafe')) return 'cafe';
  if (path.includes('Temple'))                             return 'temple';
  return 'index';
}

// ─── Aplica las traducciones al DOM ───────────────────
function applyTranslations(lang) {
  const page = getPage();
  const t = translations[page][lang];
  if (!t) return;

  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (!t[key]) return;
    if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = t[key];
    } else {
      el.textContent = t[key];
    }
  });

  localStorage.setItem('lang', lang);
}

// ─── Inicializa el select y escucha cambios ────────────
document.addEventListener('DOMContentLoaded', () => {
  const select = document.getElementById('languageSelect');
  if (!select) return;

  const saved = localStorage.getItem('lang') || 'EN';
  select.value = saved;
  applyTranslations(saved);

  select.addEventListener('change', () => {
    applyTranslations(select.value);
  });
});